import React, { useState, useMemo } from 'react';
import { ThemeProvider, createTheme, CssBaseline, Switch, AppBar, Toolbar, Typography } from '@mui/material';
import { blue, deepPurple } from '@mui/material/colors';

const App = () => {
  const [darkMode, setDarkMode] = useState(true);

  const theme = useMemo(() => createTheme({
    palette: {
      mode: darkMode ? 'dark' : 'light',
      primary: deepPurple,
      secondary: blue,
      background: {
        default: darkMode ? '#191919' : '#f5f5f5',
        paper: darkMode ? '#24242b' : '#fff',
      },
      text: {
        primary: darkMode ? '#fff' : '#000',
        secondary: darkMode ? '#abb2bf' : '#333',
      },
    },
  }), [darkMode]);

  return (
    <ThemeProvider theme={theme}>
      <CssBaseline /> {/* This applies the global styles */}

      <AppBar position="sticky">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>
            Dark / Light Mode
          </Typography>
          <Switch checked={darkMode} onChange={() => setDarkMode(prev => !prev)} />
        </Toolbar>
      </AppBar>

      <div style={{ padding: '20px', textAlign: 'center' }}>
        <h1>Welcome to My Dark/Light Mode App</h1>
        <p>Toggle the switch in the header to switch between dark and light mode.</p>
      </div>
    </ThemeProvider>
  );
};

export default App;
